INSERT INTO tags (id, slug, name, category, sort_order) VALUES ('eda033cb-2717-4eb3-86fa-cc25fdbc3dc5', 'trail', 'トレイル', 'terrain', 4);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b54bee81-d73d-40d9-9bd1-53c6c82be1ea', 'akagi-kurobisan-trail', '赤城山・黒檜山', 'あかぎやま・くろびさん', '群馬県', '前橋市', 36.543891, 139.187748, '大沼湖畔の赤城公園ビジターセンターから湖畔の道で赤城神社を経て黒檜山登山口へ。岩場の急登で赤城山最高峰の黒檜山(1828m)に立ち、稜線を駒ヶ岳(1685m)へ縦走して木段を下り、覚満淵の湿原に寄って戻る約6.5kmの周回トレイル。湖畔からの登り標高差は約450m、獲得標高は約540m。ビジターセンターにトイレ・自販機・無料駐車場とバス停がある。', 'JR前橋駅から関越交通バスで約1時間「あかぎ広場前」下車。ビジターセンターに無料駐車場', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640240000, 1783640241278);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('ce21e4f2-503c-47b5-9b6e-86f965fe3322', 'akiyoshidai-karst-trail', '秋吉台', 'あきよしだい', '山口県', '美祢市', 34.223622, 131.307186, '秋吉台観光交流センターを起点に、日本最大級のカルスト台地を北端の地獄台まで縦断し、原生林の長者ヶ森を経て戻る約13km。台地上は樹木がほとんどなく、石灰岩の白い岩肌と草原が360度広がる爽快なトレイル。途中にトイレ・自販機は無いので出発前に交流センターで済ませ、水分は多めに携行を。夏場は日陰が無く、草原の分岐は標識が少ないため地図アプリでのこまめな現在地確認が必須。', '秋吉台観光交流センター(バス停併設)が起点。無料駐車場・コインロッカーあり', 1, 0, 0, 1, 0, 0, 1, 0, 'dark', NULL, 1, 1783639088000, 1783639089648);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('aedcc35e-c955-4257-b0d0-a80b9f1968e1', 'aoshima-kisakihama', '青島〜木崎浜・県総合運動公園', 'あおしま〜きさきはま・けんそうごううんどうこうえん', '宮崎県', '宮崎市', 31.799654, 131.466908, 'JR青島駅を起点に日向灘沿いを北上し、サーフポイントとして名高い木崎浜の松林を抜ける自転車道を通って、実業団や強豪校が合宿で走ることで知られる宮崎県総合運動公園のクロスカントリーコース入口まで行って戻る約8.9kmの往復。青島太平洋マラソンのコースとも重なる海沿いの平坦路で、朝日を浴びながらのモーニングランが気持ちいい。青島側では「鬼の洗濯板」で知られる青島観光も組み合わせられる。', 'JR日南線 青島駅すぐ / 運動公園駅(折返し側)', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783638283000, 1783638285915);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('7056466e-c0d0-49b5-a919-69f0658ae05c', 'asuka-history-loop', '飛鳥周遊(橿原公苑〜石舞台古墳)', 'あすかしゅうゆう(かしはらこうえん〜いしぶたいこふん)', '奈良県', '橿原市', 34.488879, 135.791607, '橿原公苑を起点に明日香村を反時計回りに巡る約14.7kmの周回コース。前半は飛鳥寺や飛鳥宮跡を通る平坦な里道、中盤は石舞台古墳から棚田の広がる稲渕地区へ登る起伏区間、終盤は高松塚古墳のある国営飛鳥歴史公園を抜けて飛鳥駅前から戻る。田園と史跡が連続する明日香らしい景観をまとめて味わえる。観光地のため自販機・トイレは各所にあり、石舞台や飛鳥駅周辺で補給できる。', '近鉄 橿原神宮前駅から約1km(橿原公苑) / 飛鳥駅(コース終盤)', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783638283000, 1783638284928);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b7c4060b-568d-4f4e-bf1e-5d0e4850f655', 'asuwayama-loop', '足羽山', 'あすわやま', '福井県', '福井市', 36.062356, 136.217647, '福井市中心部の大手から足羽川を渡り、愛宕坂の石畳と石段を上って足羽神社、標高約116mの足羽山山頂(継体天皇像)まで登る約5.7kmの周回。下りは公園の遊歩道で川へ戻り、足羽川堤防の桜並木を走って市街へ帰る。山頂一帯は公園でトイレ・自販機があり、早朝は散歩の地元住民が多い。獲得標高約160m。', 'JR福井駅から約1km。足羽山公園に駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783640240000, 1783640241045);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('9af9950c-8616-4a35-a494-290f7f7cd186', 'beppu-kaigan-kamegawa', '別府湾岸・亀川〜東別府', 'べっぷわんがん・かめがわ〜ひがしべっぷ', '大分県', '別府市', 33.323899, 131.495747, 'JR亀川駅近くの海岸から別府市の湾岸を南下し、松林の遊歩道が心地よい上人ヶ浜公園、砂浜沿いのSPAビーチ、ヤシ並木の的ヶ浜公園を経て東別府駅前で折り返す約13.6kmの往復コース。別府湾と対岸の大分市街、振り返れば湯けむりの上がる山手の街並みを眺められる。的ヶ浜公園と上人ヶ浜公園にトイレ・自販機があり、コンビニも国道10号沿いに点在。別府駅前泊のトラベルランにも組み込みやすい。', 'JR日豊本線 亀川駅から約400m / 別府駅(コース中間)', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783638283000, 1783638284690);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('d0377983-7e05-4996-9afb-9c68188ff369', 'betsudai-kokudo-oita', 'かんたん港園〜別大国道(大分側)', 'かんたんこうえん〜べつだいこくどう(おおいたがわ)', '大分県', '大分市', 33.246631, 131.584377, '大分港近くのかんたん港園を起点に、別府大分毎日マラソンの舞台として知られる別大国道(国道10号)沿いの歩道を西進し、西大分・白木海岸・田ノ浦ビーチを経て東別府駅前で折り返す約15.5kmの往復コース。左手に別府湾、正面に高崎山を望みながら信号がほとんどない広い歩道を走れるため、ペース走やロング走に向く。中間の田ノ浦ビーチにトイレと自販機があり補給しやすい。', 'JR西大分駅から約1km / 大分駅から約2.5km', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783638283000, 1783638284436);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b08e9aad-a675-4118-825d-fcec927cd89d', 'boso-no-mura-sakatagaike', '坂田ヶ池・房総のむら周回', 'さかたがいけ・ぼうそうのむらしゅうかい', '千葉県', '成田市', 35.816506, 140.278068, '坂田ヶ池総合公園の駐車場を起点に、池のほとりから体験博物館「房総のむら」と龍角寺古墳群の雑木林を巡る里山クロカン周回。大半が未舗装の林間コースで、夏でも木陰が続き森林浴気分で走れる。激坂はなく全区間走れる程度のアップダウンが続くので、不整地トレーニングにちょうどよい。国内最大級の方墳・岩屋古墳のすぐ近くを通る。起点駐車場にトイレと自販機あり。池周辺以外は人が少なく静か。', 'JR成田線下総松崎駅から坂田ヶ池総合公園まで徒歩約15分。駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783634569000, 1783634583151);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('54105232-6b5d-4dd2-9167-c055aef8815b', 'daibosatsu-trail', '大菩薩嶺', 'だいぼさつれい', '山梨県', '甲州市', 35.731793, 138.832266, '上日川峠(ロッヂ長兵衛前)から福ちゃん荘を経て唐松尾根を登り、雷岩から標高2057mの大菩薩嶺山頂を踏んで、稜線を大菩薩峠(介山荘)へ下る反時計回り周回約7.6km。雷岩から峠までの稜線は視界が開け、晴れれば富士山と上日川ダムを一望できる。獲得標高は約460mだが道はよく整備され、トレラン入門の定番。上日川峠と福ちゃん荘、介山荘にトイレ・売店あり。岩場やすれ違いでは歩いて安全第一に。', '甲斐大和駅からバスで上日川峠へ(冬季運休あり)。峠に無料駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783639088000, 1783639089883);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('4c400708-2694-45be-ad1c-be9d68b6cf73', 'dogo-matsuyama-castle', '道後温泉・城山公園', 'どうごおんせん・しろやまこうえん', '愛媛県', '松山市', 33.851772, 132.787184, '道後温泉本館そばを起点に平和通りを西へ進み、松山城のある城山をぐるりと囲む堀端と城山公園を2周してから道後温泉へ戻る約12.4kmの周回。堀端は歩道が広く走りやすい。走り終えたらそのまま道後温泉で汗を流せるのが最大の魅力。', '伊予鉄道後温泉駅から徒歩約3分', 1, 0, 0, 0, 0, 1, 0, 1, 'partial', NULL, 1, 1783640625000, 1783640625980);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('69b825b0-8303-4cda-b01e-78e13a8a3f48', 'ezuko-lakeside', '江津湖', 'えづこ', '熊本県', '熊本市', 32.788477, 130.734267, '水前寺成趣園にほど近い上江津湖の北端を起点に、湖畔の遊歩道で上江津湖を巡り、熊本市動植物園の脇を通って下江津湖の南端まで南下して折り返す約10.5km。阿蘇の伏流水が湧く水辺は野鳥が多く、ほぼフラット。トイレが点在しロング走の練習にも使いやすい。', '熊本市中心部から車で約15分。公園周辺に駐車場あり', 1, 0, 0, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783640625000, 1783640627645);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('53853353-6aeb-4a41-959d-e160a0de8f1d', 'futagoyama-moritogawa', '二子山・森戸川林道', 'ふたごやま・もりとがわりんどう', '神奈川県', '逗子市', 35.298483, 139.600941, 'JR横須賀線・東逗子駅から尾根道で逗子市・葉山町の最高峰二子山(上二子山207m)へ登り、森戸川の源流部へ下って川沿いの平坦な林道を西へ抜け、逗子駅へ至る片道約9kmのコース。源流部はシダが生い茂る沢沿いの道で小さな渡渉が数回あり、雨後はぬかるみやすい。森戸川林道はバードウォッチングの人気スポット。下山口の川久保交差点近くにコンビニがある。', '起点=JR東逗子駅、終点=JR逗子駅', 1, 0, 0, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783636248000, 1783636265513);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('c0abc5a7-ef2c-46cb-b3f8-84d6a7fcd1dc', 'ginzan-onsen', '銀山温泉・白銀公園', 'ぎんざんおんせん', '山形県', '尾花沢市', 38.570434, 140.530143, '大正ロマンの木造旅館が銀山川の両岸に並ぶ銀山温泉街を抜け、最奥の白銀の滝から白銀公園の遊歩道へ入る渓谷沿いの往復コース。かつての延沢銀山の坑道跡・銀鉱洞を経て川の上流で折り返す。石畳や木道、石段が混じるので足元に注意。距離は短いが見どころが濃く、宿泊ランや湯上がり前のひと走りにちょうどよい。公衆浴場「しろがね湯」が温泉街入口にある。', 'JR大石田駅から路線バスまたは宿の送迎で約40分。温泉街手前の駐車場が起点', 1, 0, 0, 0, 0, 1, 1, 0, 'dark', NULL, 1, 1783637164000, 1783637179144);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('8252d304-03fd-4ef7-951a-dce1c19e2772', 'hanasono-kurotaki-trail', '黒滝・花園トレイル', 'くろたき・はなそのとれいる', '千葉県', '南房総市', 35.0581, 140.025078, '南房総市和田町花園の広場を起点に、花園川の黒滝に立ち寄ってから烏場山東側の尾根に上がり、雑木林の山道を北西へたどって折り返す約8.6kmの往復トレイル。累積約320mで走れる区間が多く、ビギナーのトレイル練習にちょうどよい。温暖な南房総なので冬から早春のトレーニングにも向く。起点にトイレと駐車スペースがあるが、そこまでの道が狭いため大きな車は注意。コース上に自販機や水場はないので飲料は持参を。', '車:はなその広場駐車場(JR内房線和田浦駅から約3km)', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783635436000, 1783635451007);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('e52b0e7d-e1ed-4e72-a03f-a166a0ee86bf', 'hanno-four-peaks', '飯能三山・天覧山めぐり', 'はんのうさんざん・てんらんざんめぐり', '埼玉県', '飯能市', 35.850666, 139.318845, '飯能駅を発着して天覧山(197m)・多峯主山(271m)を越え、入間川沿いに下って吾妻峡を渡り、飯能三山の龍崖山(246m)・柏木山(303m)まで足を延ばす低山4座の周回。市街地からすぐトレイルに入れるのが飯能の魅力で、一つひとつは低いものの急な登り返しが続き、通しで走り切るには相応の脚力がいる。龍崖山公園にトイレあり。駅前に飲食店やコンビニが揃い、ラン後の補給にも困らない。', '西武池袋線飯能駅から徒歩すぐ', 1, 0, 0, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783634569000, 1783634582381);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b00c69a1-9b9b-4f3b-8a3c-b87678ec1291', 'hatonosu-otake-seoto', '大岳山縦走(鳩ノ巣〜瀬音の湯)', 'おおだけさんじゅうそう(はとのす〜せおとのゆ)', '東京都', '西多摩郡奥多摩町', 35.815029, 139.128929, 'JR青梅線鳩ノ巣駅から尾根を登って御岳山(929m)へ、綾広の滝の脇を抜けて奥多摩三山の大岳山(1,266m)に立ち、馬頭刈尾根を馬頭刈山(884m)経由で秋川渓谷まで下るワンウェイ縦走。獲得標高約1,600mの本格トレイルで、大岳山頂直下には岩場もある。ゴールは温泉施設「秋川渓谷 瀬音の湯」で、汗を流してからバスで武蔵五日市駅へ戻れる。御岳山の宿坊集落に売店とトイレあり。', 'スタートはJR青梅線鳩ノ巣駅。ゴールの瀬音の湯からは西東京バスで武蔵五日市駅へ約20分', 1, 0, 0, 0, 0, 1, 0, 0, 'dark', NULL, 1, 1783634569000, 1783634582116);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('48ea4ff4-4473-461c-9b21-99e8cd877a59', 'hibarako-loop', '桧原湖', 'ひばらこ', '福島県', '耶麻郡北塩原村', 37.664572, 140.044657, '裏磐梯の最大湖・桧原湖を湖岸道路(県道64号と国道459号)でつなぐ一周約31.7km。合宿ランナーの定番周回で、細かなアップダウンが連続する走り応えのあるコース。南岸は五色沼入口や裏磐梯物産館など観光エリアでトイレ・売店・自販機が使え、西岸・北岸は交通量が少なく静か。標高800m超なので夏でも比較的涼しい。', '磐越道 猪苗代磐梯高原ICから約25分。南岸の観光施設に駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783637356000, 1783637357418);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('09aeabc8-2376-45d5-901c-89b9e0d7f594', 'himi-amaharashi', '比美乃江公園〜雨晴海岸', 'ひみのえこうえん〜あまはらしかいがん', '富山県', '氷見市', 36.86921, 136.985007, '氷見漁港前の比美乃江公園から、ひみ番屋街を経て富山湾沿いを南下し、万葉集にも詠まれた景勝地・雨晴海岸を通ってJR雨晴駅まで走る約8.3kmのワンウェイ。空気が澄んだ日は海越しに立山連峰が浮かぶ北陸屈指の絶景ルートで、並走するJR氷見線の車両と海を一緒に望める。高低差はほぼなく、道の駅雨晴や海岸沿いの公園にトイレ・自販機が点在。帰りは氷見線で戻れる。', 'JR氷見線 氷見駅から約1.2km(スタート) / 雨晴駅(ゴール)', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783638283000, 1783638286159);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('8fd2c358-3519-4ca8-9568-6de899858008', 'hirosaki-park-loop', '弘前公園(弘前城)', 'ひろさきこうえん', '青森県', '弘前市', 40.599008, 140.484703, 'JR弘前駅から広い歩道の続く市街地を約2km走り、弘前公園を園内経由でめぐって戻る周回コース。追手門から入り、弘前城本丸の下を抜けて北門(亀甲門)へ、帰りは外濠沿いを走れる。園内には約2,600本の桜があり、4月下旬は濠を花びらが埋める花筏や桜のトンネルが圧巻。観光客が少ない早朝が走りやすい。', 'JR弘前駅中央口から弘前公園追手門まで約2km', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783637164000, 1783637177979);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('fb414b41-029b-486b-94fc-1cf73f09dd6a', 'hokyosan-loop', '宝篋山周回(小田・常願寺コース)', 'ほうきょうさんしゅうかい(おだ・じょうがんじこーす)', '茨城県', 'つくば市', 36.174902, 140.103818, '北条大池のほとり(大池公園)を起点に、筑波山の南に立つ宝篋山(461m)をぐるりと回る周回コース。麓の道で小田城跡のある小田集落へ回り込み、小田休憩所から常願寺コースで尖浅間(315m)を経て山頂へ。山頂からは筑波山と関東平野、霞ヶ浦まで見渡せる大展望が広がる。下山は北西側の尾根道で大池公園へ。登山道は必要最小限の整備で自然な土の道が残り、案内標識は要所に揃っていて迷いにくい。小田休憩所と大池公園にトイレあり。', '大池公園(北条大池)駐車場が起点。常磐道土浦北ICから車で約15分', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783634569000, 1783634583413);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('5c68882a-8057-4e45-ab7a-94f925e74e71', 'imabari-castle-port', '今治城・今治港', 'いまばりじょう・いまばりこう', '愛媛県', '今治市', 34.065036, 132.995072, '今治駅前から港へ向かい、今治港の旅客ターミナル(みなと交流センター)周辺と今治城の堀端をめぐって駅へ戻る約4kmの周回。今治城は海水を引き込んだ堀が特徴で、堀端はフラットで歩道も整備されている。朝ランや旅ランのショートコースにちょうどよい。', 'JR今治駅からすぐ', 1, 0, 0, 0, 0, 0, 1, 1, 'partial', NULL, 1, 1783640625000, 1783640626211);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('96130b67-6cc2-4df9-a89a-6eed7d411d36', 'irozaki-seaside-trail', '石廊崎・奥石廊トレイル', 'いろうざき・おくいろうとれいる', '静岡県', '賀茂郡南伊豆町', 34.609587, 138.842313, '伊豆半島最南端、石廊崎の遊覧船乗り場駐車場を起点に石廊崎灯台へ往復したあと、海を見下ろすハイキング道で中木集落方面へ抜け、帰路はあいあい岬・ユウスゲ公園を通る県道16号の絶景シーサイドロードで戻る約10.9kmの周回。累積約390mとアップダウンは多めだが、断崖と青い海の景色が続く。駐車場とあいあい岬に売店・自販機・トイレあり。山道区間は夏場に草が茂るため肌の露出を抑えた服装が安心。', '車:石廊崎オーシャンパーク駐車場/バス:伊豆急下田駅から石廊崎方面行き', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783635436000, 1783635449422);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('f490d9c0-24cf-4102-ac0d-6f4fccb3d0ff', 'isaka-dam', '伊坂ダム', 'いさかだむ', '三重県', '四日市市', 35.040836, 136.620227, '四日市北部の伊坂ダム湖畔を回る1周約3.5kmの周回路。車が入らない舗装路で信号ゼロ、緑に囲まれた湖面を見ながら走れる。起伏が連続するので周回を重ねれば起伏走のトレーニングに、1周だけならリフレッシュランにちょうどいい。サイクルパークの管理棟にトイレ・自販機があり、レンタサイクルや無料駐車場も揃う。', '東名阪道 四日市東ICから約5分。伊坂ダムサイクルパーク駐車場(無料)', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783637356000, 1783637358825);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('5c2b5a96-d7cb-49af-bb59-c44c2ad7a135', 'iwadono-kyuryo-cross', '岩殿丘陵(物見山・岩殿観音)', 'いわどのきゅうりょう(ものみやま・いわどのかんのん)', '埼玉県', '東松山市', 36.002832, 139.396662, '東武東上線高坂駅西口から旧日本セメント専用線の廃線跡を転用した遊歩道を西へ進み、大東文化大学前の急坂を上って岩殿観音(正法寺)と物見山公園へ。JAXA地球観測センター前まで足を延ばし、こども動物自然公園前を通って駅に戻る約15.5kmの丘陵周回。舗装路と土の道が交互に現れ、起伏走やクロカン練習に向く。物見山公園と岩殿観音周辺にトイレ・自販機あり。', '東武東上線 高坂駅', 1, 0, 1, 0, 0, 0, 0, 0, 'partial', NULL, 1, 1783635436000, 1783635448906);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('84c26646-10a3-46f6-ae39-03b0acd56964', 'izumo-taisha-run', '出雲市駅〜出雲大社', 'いずもしえき〜いずもたいしゃ', '島根県', '出雲市', 35.36051, 132.756707, 'JR出雲市駅から北西へ、出雲平野の田園地帯を抜けて縁結びの神様・出雲大社を目指す片道約9.4km。終盤は明治の木造駅舎が残る旧大社駅(重要文化財)を通り、宇迦橋の大鳥居から石畳の神門通りを上って勢溜の正門鳥居がゴール。高低差は50m弱とほぼ平坦で、沿道にコンビニや自販機が点在するため補給とトイレの心配が少ない。復路は一畑電車やバスで戻れるので出張朝ランにも使いやすい。', '起点はJR出雲市駅。帰りは一畑電車出雲大社前駅やバスを利用可', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783639088000, 1783639091318);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('8058cae5-1ccf-4c50-912d-5d2177cdea3b', 'kagamigawa-riverside', '鏡川', 'かがみがわ', '高知県', '高知市', 33.556345, 133.532936, '高知市中心部を流れる鏡川の北岸を、柳原付近から鏡川橋まで遡って戻る約6.9kmの往復コース。堤防上には車道と分かれた遊歩道が続き、信号に止まらず走れる。ほぼ完全にフラットで、川面と筆山を眺めながらのジョグに向く。散歩やランニングの地元利用が多く、上流・下流へ足を延ばして距離を調整しやすい。', 'とさでん交通伊野線・県庁前電停や鏡川橋電停から徒歩すぐ', 1, 0, 0, 0, 0, 0, 0, 0, 'partial', NULL, 1, 1783640240000, 1783640242463);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('7a3bc75d-df30-4e30-853f-308a8862f178', 'kaike-onsen-coast', '皆生温泉海岸', 'かいけおんせんかいがん', '鳥取県', '米子市', 35.458793, 133.361565, '皆生温泉の海岸遊歩道から日本海(美保湾)沿いを西へ進み、日野川を渡って弓ヶ浜公園で折り返して市街地の道で戻る約9.5kmの周回。ほぼ完全フラットで信号も少なく、朝日と弓ヶ浜のカーブ、大山を望む海岸線が気持ちいい。途中に松の防風林があり、風の強い日は林間の道に逃げられる。ゴール後は温泉街の日帰り湯へ直行できる。', 'JR米子駅からバス約20分「皆生温泉観光センター」下車', 1, 0, 0, 0, 0, 1, 0, 1, 'partial', NULL, 1, 1783637356000, 1783637358592);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('548f7ebd-7af4-444e-b041-873de1e107a3', 'kamakura-issyu-trail', '鎌倉トレイル大周回', 'かまくらとれいるだいしゅうかい', '神奈川県', '鎌倉市', 35.352889, 139.531718, '大船駅を起点に六国見山、建長寺半僧坊から天園ハイキングコース(鎌倉アルプス)、瑞泉寺、衣張山、名越切通と鎌倉の街を取り囲む尾根と切通しをロードでつなぎ、長谷から大仏切通・葛原岡・山崎台峯緑地を経て大船へ戻る約23kmの周回ロング。土のトレイルと舗装路が交互に現れ、社寺やトイレ・自販機の補給ポイントが点在するのでロング走の練習に向く。', 'JR大船駅から徒歩数分', 1, 0, 1, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783636248000, 1783636264019);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b3fef2ea-0fcc-4bdb-b759-5eb5234a1626', 'kamakura-kiridoshi-loop', '鎌倉切通し巡りトレイル', 'かまくらきりどおしめぐりとれいる', '神奈川県', '鎌倉市', 35.318584, 139.551197, '鎌倉駅東口から鎌倉宮を経て天園ハイキングコースに入り、鎌倉市最高点の大平山(159m)から市境の尾根で大丸山(157m)へ立ち寄り、鎌倉七口のひとつ朝夷奈切通を下る。逗子側の久木大池から名越切通を抜けて駅へ戻る約17.6kmの周回。中世の切通しの岩壁と照葉樹の森が続き、急登が少ないためトレイル初級者のステップアップに向く。途中の熊野神社や天園休憩所が目印。', 'JR横須賀線・江ノ島電鉄鎌倉駅', 1, 0, 1, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783636248000, 1783636264519);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('4b3eadd1-3689-4896-a072-bc897ba9ed59', 'kamiyama-amagoi-higanji', '雨乞の滝・悲願寺', 'あまごいのたき・ひがんじ', '徳島県', '名西郡神山町', 33.962347, 134.34739, '雨乞の滝駐車場から谷沿いの遊歩道を登り、日本の滝百選の雨乞の滝を経て尾根道を標高約700mの悲願寺まで登るトレイル周回。復路は集落を縫う舗装林道を下り、国道438号沿いに戻る。獲得標高約780mと登り応えがあり、登りは山道・下りは舗装の混合路面。', '徳島市中心部から車で約50分。雨乞の滝入口駐車場を利用', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640625000, 1783640625744);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('c998de60-d466-4fa1-826c-19aeab614a48', 'kanmon-kaikyo-crossing', '関門海峡横断(下関〜門司港)', 'かんもんかいきょうおうだん', '山口県', '下関市', 33.950917, 130.925001, '下関駅から海沿いに唐戸市場・赤間神宮・みもすそ川公園(壇之浦古戦場跡)を巡り、関門トンネル人道(全長約780m・徒歩無料)で海峡を渡って九州へ。門司側は和布刈公園の坂を越え、めかり街道からブルーウィングもじ・旧門司税関のレトロ地区を抜けて門司港駅がゴールの約8.8km。人道は6時〜22時通行可でランナーも多い。コンビニ・自販機・トイレは随所にある。', '起点はJR下関駅、ゴールはJR門司港駅。電車で下関へ戻れる', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783639088000, 1783639089387);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('2bde01d2-dca9-4fae-94d9-2eea7168a033', 'kasugayama-wakakusayama-trail', '春日山遊歩道・若草山周回', 'かすがやまゆうほどう・わかくさやましゅうかい', '奈良県', '奈良市', 34.684219, 135.8282, '近鉄奈良駅を起点に興福寺・浮見堂・春日大社を経て、石畳の旧柳生街道「滝坂の道」を首切地蔵まで登り、世界遺産・春日山原始林の縁を走る春日山遊歩道から若草山山頂(342m)へ抜ける約14kmの周回。山頂からは奈良盆地と大仏殿の大屋根を一望できる。下りは二月堂・東大寺南大門を通って市街へ戻る。獲得標高約540mで、市街地と原生林トレイルが半々の初心者向けトレラン入門コース。奈良公園一帯は鹿が多く、観光地なのでトイレ・自販機に困らない。', '近鉄奈良線 近鉄奈良駅すぐ', 1, 0, 1, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783638283000, 1783638285169);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('2888f86e-4b06-46c4-98fc-aacd9ae7e707', 'kii-tanabe-ogigahama', '紀伊田辺・扇ヶ浜', 'きいたなべおうぎがはま', '和歌山県', '田辺市', 33.733691, 135.384089, 'JR紀伊田辺駅を起点に、熊野古道(紀伊路・中辺路)ゆかりの世界遺産・闘鶏神社の前を通って扇ヶ浜海岸へ下りる街なか周回コース。弓状に開けた扇ヶ浜のビーチ沿いを走り、漁港側から市街地へ戻る。信号の少ない海沿い区間は透明度の高い田辺湾を眺められ、駅前泊の出張ランや旅ランの朝にちょうどよい距離感。', 'JR紀伊田辺駅から徒歩すぐ', 1, 0, 0, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783637164000, 1783637178211);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('06d6e971-52b6-493c-8440-808710c2ddb3', 'king-skyfront-tamagawa', '多摩川河口・キングスカイフロント', 'たまがわかこう・きんぐすかいふろんと', '神奈川県', '川崎市川崎区', 35.54081, 139.753798, '川崎市殿町のキングスカイフロント地区を起点に、多摩川スカイブリッジのたもとから多摩川右岸沿いを大師橋まで往復する約5.3kmのフラットコース。対岸に羽田空港が広がり、離着陸する飛行機を眺めながら信号にほぼ止まらず走れる。研究施設街のため歩道が広く夜も人通りが少なめ。周辺のホテルや公園でトイレ・自販機を利用できる。スカイブリッジを渡れば羽田空港側にも行ける。', '京急大師線 小島新田駅 徒歩約15分/多摩川スカイブリッジ経由で羽田空港第3ターミナル', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783635436000, 1783635449164);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('e93d9380-2829-471d-9c74-867d15cdf124', 'kinugawa-onsen', '鬼怒川温泉', 'きぬがわおんせん', '栃木県', '日光市', 36.823495, 139.713509, '鬼怒川温泉の温泉街を起点に、歩行者用のふれあい橋で東岸へ渡って会津西街道を北上し、吊橋の滝見橋で渓谷を渡り返す周回コース。北側では鬼怒川沿いの静かな道を約1.4km往復する。渓谷地形のため獲得標高は約120mあり、橋上からの川の眺めが良い。吊橋は揺れるので歩いて渡るのが安全。', '東武鬼怒川温泉駅から徒歩約10分', 1, 0, 0, 0, 0, 1, 1, 1, 'partial', NULL, 1, 1783640625000, 1783640626442);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('13d06bc9-180b-44fc-a667-f151453b1c8d', 'kinuta-park-cross-country', '砧公園クロカンコース', 'きぬたこうえんくろかんこーす', '東京都', '世田谷区', 35.629039, 139.620073, '元は都営ゴルフ場だった砧公園の、うねりのある芝生と木立を生かした1周約1.7kmの内周コース。適度な起伏の不整地を周回するクロスカントリー走ができ、実業団や大学の長距離チームも練習に訪れる。芝生の上にはランナーが踏み固めた細い走路が浮かび上がっており、初めてでも迷わず周回できる。木の根の張り出しには注意。園内は桜の名所で、1周約1.7kmのサイクリングロード外周と組み合わせれば距離も伸ばせる。トイレ・自販機・有料駐車場あり。', '東急田園都市線用賀駅から徒歩約20分。東名高速東京IC至近(有料駐車場あり)', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783634569000, 1783634582904);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('0b35ea48-a98c-4f87-b3f1-3fcd51c82a83', 'kitakamakura-daibutsu-enoshima', '大仏ハイキングコース・湘南海岸', 'だいぶつはいきんぐこーす・しょうなんかいがん', '神奈川県', '鎌倉市', 35.336747, 139.545212, '北鎌倉駅から浄智寺脇の登山口で葛原岡・大仏ハイキングコースに入り、葛原岡神社・源氏山公園を経て鎌倉大仏(高徳院)へ抜ける前半約4kmの土のトレイル。長谷からは国道134号沿いの歩道に出て、稲村ヶ崎・七里ヶ浜と湘南の海岸線を西へ走り、江の島弁天橋を往復してから境川沿いに藤沢駅へ至る片道コース。山の緑と海の展望を一度に味わえる。', '起点=JR横須賀線北鎌倉駅、終点=JR東海道線藤沢駅', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783636248000, 1783636263534);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('93191dc4-79c0-4a6f-ac67-a5ae7e6c111b', 'kitakami-river-morioka', '北上川河川敷(盛岡)', 'きたかみがわかせんじき(もりおか)', '岩手県', '盛岡市', 39.692309, 141.143989, '明治橋近くの左岸を起点に、北上川沿いの堤防道と河川敷の道を南へ約3km下って折り返す往復約6.1kmのコース。高低差はほとんどなく信号にも邪魔されないので、ジョグからペース走まで淡々と走り込みたい日に向く。帰路の北向きでは晴れると正面に岩手山が見え、四季の川辺の景色も楽しめる。河川敷なので夜間は暗く、日中の利用がおすすめ。さらに南へ道が続くので距離を伸ばすこともできる。', 'JR盛岡駅から明治橋まで約1.5km', 0, 0, 0, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783639088000, 1783639091070);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('70dd2cbc-7a55-48cb-8b21-b5c61e2de574', 'kouri-island', '古宇利島', 'こうりじま', '沖縄県', '国頭郡今帰仁村', 26.696428, 128.01847, '古宇利大橋北詰の古宇利ビーチを起点に、全長約2kmの古宇利大橋(歩道あり)を屋我地島側まで往復してから、島の外周道路を一周する約10.6km。橋の上は左右にエメラルドグリーンの海が広がる爽快な直線。島内はサトウキビ畑の間を抜ける起伏のある道で、獲得標高は約90m。', '沖縄自動車道許田ICから車で約40分。古宇利ビーチ周辺に駐車場あり', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640625000, 1783640626941);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('a7d722e7-2dee-461c-88f2-a2e51265e9db', 'kurashiki-setouchi', '倉敷〜宇野港', 'くらしき〜うのこう', '岡山県', '倉敷市', 34.607288, 133.762386, '倉敷駅から白壁の美観地区を抜けて南下し、児島駅から瀬戸内海沿いへ。渋川海岸の白砂のビーチと王子が岳の麓を通り、玉野市の宇野駅・宇野港まで走り切る約36kmのロングラン。前半は平坦な市街地・田園地帯、児島以降は海を見ながらのアップダウンが続く(獲得標高約320m)。コンビニは前半に多く後半の海沿いは少なめなので補給計画を。ゴールの宇野港には温浴施設があり、帰りはJR宇野線で戻れる。', '起点はJR倉敷駅、ゴールはJR宇野駅。電車で倉敷へ戻れる', 1, 0, 1, 0, 0, 1, 0, 1, 'partial', NULL, 1, 1783639088000, 1783639090362);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('e292225b-aa8a-4ab8-b0a1-c86b624ad823', 'kurashiki-sports-park', '倉敷スポーツ公園', 'くらしきすぽーつこうえん', '岡山県', '倉敷市', 34.61712, 133.804068, 'プロ野球公式戦も開かれるマスカットスタジアムを擁する倉敷スポーツ公園の園路を1周する約2kmの周回コース。園内にはアスファルト舗装のほか土や芝生の区間もあり、目的や脚の調子に合わせて路面を選んで走れるのが特徴。道幅が広くフラットで、ジョグからスピード練習まで使いやすい。園内にトイレ・自販機があり、夜間は照明も点くのでナイトランも可能。JR中庄駅から徒歩圏内で駐車場も広い。', 'JR山陽本線中庄駅から徒歩約15分。無料駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783639088000, 1783639090600);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('51867139-c86a-46e0-bdc8-ebe0d7b7f764', 'kuroshio-line-niyodo', '黒潮ライン・仁淀川河口大橋', 'くろしおらいん・によどがわかこうおおはし', '高知県', '高知市', 33.499459, 133.549909, '桂浜の西、浦戸大橋のたもと近くから県道春野赤岡線(黒潮ライン)を西へ。太平洋を左手に海岸線をほぼ一直線に走り、全長約1kmの仁淀川河口大橋を渡って土佐市新居の観光交流施設「南風」で折り返す約18kmの往復。信号がほとんどなくフラットで、高知龍馬マラソンのコースにも使われる区間の試走に向く。折り返し点の南風でトイレと自販機補給ができる。', '高知市中心部から車で約20分。南風に駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640240000, 1783640242698);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('1287f3dd-32b9-4656-beea-bc1e2714558f', 'mabori-kaigan-umikaze', '馬堀海岸・うみかぜの路', 'まぼりかいがん・うみかぜのみち', '神奈川県', '横須賀市', 35.263631, 139.716292, '馬堀海岸の海沿い遊歩道「うみかぜの路」を軸に、東は走水を経て観音崎公園まで、西は海辺つり公園方面まで往復する約12.6kmのシーサイドコース。目の前に東京湾と猿島が広がり、空気の澄んだ冬は富士山も見える。馬堀海岸区間は歩車分離で信号なしのフラットな遊歩道、走水〜観音崎間にだけ緩い起伏がある。観音崎公園と海辺つり公園にトイレ・自販機あり。米海軍基地が近く外国人ランナーも多い。', '京急本線 馬堀海岸駅 徒歩約5分', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783635436000, 1783635449707);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('9a81d842-4c21-481a-bbcb-bd557ade9834', 'madarao-kogen-trail', '斑尾高原トレイル(斑尾山・袴岳)', 'まだらおこうげんとれいる', '新潟県', '妙高市', 36.851278, 138.284408, 'トレランレースの舞台として知られる斑尾高原を走り込む約23kmの周回。高原の宿泊街を起点に日本三百名山の斑尾山(1,382m)へ登り、万坂峠から長野・新潟県境の尾根を袴岳(1,135m)へ縦走。ブナ林のシングルトラックを下って沼の原湿原を抜け、高原へ戻る。信越トレイルと重なる区間が多く、走れる緩斜面と急登がバランスよく続く。水場がないので携行必須。', 'JR飯山駅からバスで斑尾高原へ約30分。マイカーは上信越道豊田飯山ICから約20分', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783637164000, 1783637179632);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('3043a28b-5895-42a7-a546-e8fc3924c9e3', 'megane-bashi-heiwa-park', '眼鏡橋(中島川公園)', 'めがねばし', '長崎県', '長崎市', 32.747184, 129.880074, '日本最古級のアーチ石橋・眼鏡橋を起点に、長崎駅前から国道206号の路面電車通りを北上し、浦上の平和公園で折り返す往復約7.8km。歩道が広く走りやすいが市街地なので信号は多め。折り返し点の平和公園にはトイレ・自販機・平和祈念像があり、原爆資料館にも立ち寄れる。長崎の中心部と浦上をつなぐ観光ラン向きの一本。', '長崎電気軌道「めがね橋」電停からすぐ', 1, 0, 1, 0, 0, 0, 0, 1, 'bright', NULL, 1, 1783637356000, 1783637358359);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('ca912ab4-87f9-4eac-b7ef-728c51856402', 'minami-takao-trail', '南高尾山稜', 'みなみたかおさんりょう', '東京都', '八王子市', 35.642026, 139.282723, '高尾駅を起点に、草戸山から南高尾山稜を西へ縦走し、大垂水峠から高尾山頂へ登り返して高尾山口へ下る約19kmの周回トレイル。表高尾の喧騒と対照的に南尾根は人が少なく、走れる緩いアップダウンが長く続くのでトレラン入門の縦走練習に向く。草戸山からは城山湖、稜線の展望台からは津久井湖と丹沢が見渡せる。高尾山頂とふもと以外に自販機・トイレはないので補給は事前に。', 'JR中央線・京王線「高尾駅」南口から徒歩すぐ(登山口まで約1km)', 1, 0, 1, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783632468000, 1783632469178);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('5b8839b4-183e-4598-a516-de7a0a01bea1', 'minoyama-park', '美の山公園(蓑山)', 'みのやまこうえん(みのやま)', '埼玉県', '秩父郡皆野町', 36.070414, 139.099383, '秩父鉄道皆野駅から標高586mの蓑山山頂に広がる美の山公園までを登って戻る往復コース。登山口から尾根沿いの登山道で一気に約420mを稼ぐ本格的な坂トレーニングになる。山頂一帯は約8,000本の桜で知られ、展望台からは秩父盆地と武甲山を一望。条件が合えば早朝に雲海も見られる。園内にトイレと駐車場あり。夜間は照明がなく真っ暗なので日中向き。', '秩父鉄道皆野駅から登山口まで徒歩約10分。関越道花園ICから車で約50分(山頂駐車場あり)', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783634569000, 1783634581317);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('515603eb-074e-4697-925f-2776a05db27b', 'miyazaki-night-run', '橘通り〜宮崎神宮〜大淀川', 'たちばなどおり〜みやざきじんぐう〜おおよどがわ', '宮崎県', '宮崎市', 31.91814, 131.423551, '宮崎市の中心繁華街・橘通りから北上して神武天皇を祀る宮崎神宮へ、折り返して南西の大淀川堤防に出て川沿いを橘橋・市役所前まで下り、橘通りを北上して戻る約8.9kmの市街地周回。街路灯の多い大通りと川沿い遊歩道が中心でナイトランでも走りやすく、出張や旅行の拠点から出やすいのが魅力。コンビニと自販機は市街地に豊富、大淀川沿いはフラットで信号も少ない。', '宮崎交通 橘通り周辺バス停 / JR宮崎駅から約1km', 1, 0, 1, 0, 0, 0, 0, 1, 'bright', NULL, 1, 1783638283000, 1783638285683);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('24faac1b-bdf9-48af-bad2-8900f2f39a2c', 'morioka-city-jog', '盛岡市街名所めぐり', 'もりおかしがいめいしょめぐり', '岩手県', '盛岡市', 39.702434, 141.139751, '盛岡駅近くの開運橋を起点に、盛岡城跡公園から中津川沿いを上の橋へ、クラフトビールのベアレン醸造所本店前を通って高松の池まで北上し、福田パン長田町本店・啄木新婚の家を経て戻る約8.5kmの市街地周回。開運橋からは晴れた日に岩手山が正面に見える。信号は多めだがコンビニ・トイレに困らず、途中の高松の池は桜の名所。補給ポイントを巡る観光ジョグとして朝ランにも向く。', 'JR盛岡駅から開運橋まで徒歩約5分', 1, 0, 1, 0, 0, 0, 0, 1, 'bright', NULL, 1, 1783639088000, 1783639090836);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b857caac-c50e-4eea-9add-c196378aa196', 'nagasaki-machinaka-loop', '長崎まちなか周回コース', 'ながさきまちなかしゅうかいこーす', '長崎県', '長崎市', 32.752089, 129.872303, '長崎駅前を起点に諏訪神社、中島川沿いの眼鏡橋、新地中華街、水辺の森公園、出島、大波止と長崎の名所を一筆書きでつなぐ約6.1kmの周回。諏訪神社前後にだけ登りがあり、あとは平坦。市街地なので信号や路面電車の横断はあるが、観光前の朝ランで長崎の見どころを一気に回れる。水辺の森公園と駅にトイレあり。', 'JR長崎駅からすぐ', 1, 0, 1, 0, 0, 0, 0, 1, 'bright', NULL, 1, 1783637356000, 1783637358125);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('6ee0ae8b-6fc7-46f3-8042-c487a39d1a6b', 'naminoue-beach', '波の上ビーチ', 'なみのうえびーち', '沖縄県', '那覇市', 26.21691, 127.682314, '久茂地・県庁近くを起点に、那覇市内で唯一のビーチである波の上ビーチと、防波堤沿いの遊歩道で結ばれた波の上うみそら公園を巡る約6.5km。ほぼフラットな舗装路で信号も少なく、夕方なら海に沈む夕日を眺めながら走れる。ビーチにはトイレとシャワーがある。', 'ゆいレール県庁前駅から徒歩約10分', 1, 0, 0, 0, 1, 0, 0, 1, 'partial', NULL, 1, 1783640625000, 1783640627174);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('8cb8884b-9e3e-4ccc-9dc3-ab794b2eecab', 'niiharu-shimin-no-mori', '新治市民の森', 'にいはるしみんのもり', '神奈川県', '横浜市緑区', 35.513075, 139.511656, 'JR横浜線・十日市場駅から1kmほどでアクセスできる横浜市内有数の広さの市民の森。尾根の散策路と谷戸をつなぐ約3kmの周回で、岩場がなく走って登れる緩い坂が中心なのでトレイル入門の練習にちょうどよい。竹林や雑木林の中で野鳥の声が楽しめる。歩行者・自然観察者優先、少人数利用がローカルルール。旭谷戸広場側に無料駐車場と水飲み場がある。', 'JR横浜線十日市場駅から約1km', 1, 1, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783636248000, 1783636263767);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('bad0afce-41e6-436a-ba49-2d486b162c87', 'noguchi-mizuki-road', '倉田山公園(野口みずきロード)', 'くらたやまこうえん', '三重県', '伊勢市', 34.489556, 136.73307, '野口みずき選手の金メダル記念碑が立つ倉田山公園野球場を起点に、倭姫宮・神宮徴古館の杜から月読宮を経て伊勢神宮内宮の宇治橋前まで南下し、猿田彦神社・伊勢西IC側の側道を通って戻る約10kmの周回。周辺は野口選手が現役時代に練習していた「野口みずきロード」と呼ばれる一帯で、後半に起伏が続き走り応えあり。記念碑前にきれいなトイレがある。', '近鉄五十鈴川駅から徒歩約15分。倉田山公園に駐車場あり', 1, 0, 0, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783637356000, 1783637359060);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('c6fd451e-161e-4b04-be55-a73ab1c7fbf1', 'okumusashi-izugatake', '伊豆ヶ岳・子ノ権現', 'いずがたけ・ねのごんげん', '埼玉県', '飯能市', 35.938335, 139.182224, '西武秩父線・正丸駅を起点に、正丸峠から奥武蔵屈指の人気峰・伊豆ヶ岳(851m)へ登り、古御岳・高畑山・天目指峠を経て足腰守護で知られる子ノ権現天龍寺まで尾根を縦走する周回コース。下山後は西吾野から国道299号沿いの緩い下り基調で駅へ戻る。累積標高800m超で、伊豆ヶ岳直下の鎖場(男坂)には巻き道あり。子ノ権現に茶屋・トイレ・自販機がある。', '西武秩父線正丸駅すぐ', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783636248000, 1783636263282);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b03dc591-980f-47ca-b868-35b4511afe3e', 'okumusashi-yugate-monomiyama', 'ユガテ・物見山縦走路', 'ゆがて・ものみやまじゅうそうろ', '埼玉県', '飯能市', 35.892048, 139.260559, '西武線東吾野駅から尾根に取り付き、橋本山(321m)、山上集落のユガテ、鎌北湖、北向地蔵、物見山(375m)、日和田山の裾を経て高麗駅へ抜ける駅から駅への縦走コース。実測約13.2km・累積約650mで、よく踏まれた走りやすい登山道が主体。鎌北湖畔にトイレと自販機があり中間補給に使える。電車で入って電車で帰れる奥武蔵トレランの定番エリア。', '西武池袋線 東吾野駅(スタート)/高麗駅(ゴール)', 1, 0, 1, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783635436000, 1783635448389);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('69c53bb5-292d-4b03-b8d7-c55a510d06d8', 'onomichi-suido-run', '尾道水道・海岸通り', 'おのみちすいどうかいがんどおり', '広島県', '尾道市', 34.401815, 133.190013, 'サイクリストの聖地・しまなみ海道の本州側玄関口を走る街ラン周回。海運倉庫をリノベした複合施設ONOMICHI U2前のプロムナードから、向島を対岸に望む尾道水道沿いを東へ。国宝の本堂と多宝塔を持つ浄土寺まで行き、石段を上って参拝したら本通り商店街のアーケードと駅前を抜けて戻る。海風と坂のまち尾道のレトロな路地を一度に味わえる。', 'JR尾道駅から徒歩約5分(ONOMICHI U2前)', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783637164000, 1783637179386);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('3acdb50d-bc9d-4d39-a531-d965d58f37dc', 'oonoyama-hillclimb', '大野山', 'おおのやま', '神奈川県', '足柄上郡山北町', 35.360311, 139.079809, 'JR御殿場線・山北駅前の日帰り温泉「さくらの湯」を発着点に、大野山(723m)山頂まで約8.7kmを車道でひたすら登るヒルクライム練習コース。山頂一帯はかつて牧場だった開けた草原で、富士山や丹沢湖の展望が広がる。下りは地蔵岩コースの土のトレイルで共和地区へ下り、往路の道を駅まで戻る周回。獲得標高900m超とタフで、夏場の強化練習にも向く。山頂と駅にトイレあり。', 'JR御殿場線山北駅から徒歩2分', 1, 0, 1, 0, 0, 1, 0, 0, 'dark', NULL, 1, 1783636248000, 1783636265006);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('19ab63f0-f4e2-4571-91e2-a04766cfdff0', 'rainbow-bridge-odaiba', 'レインボーブリッジ・お台場', 'れいんぼーぶりっじ・おだいば', '東京都', '港区', 35.631974, 139.742992, '品川駅港南口エリアを起点に芝浦ふ頭へ進み、レインボーブリッジの遊歩道(約1.7km)で東京湾を渡ってお台場へ。お台場海浜公園からシンボルプロムナード、ダイバーシティ前を回り、同じ遊歩道で戻る約16.5kmの周回。橋上からは都心と湾岸のパノラマが広がり夜景も見事。遊歩道は開放時間制(4-10月9-21時・11-3月10-18時、第3月曜休)で通行無料・自転車走行不可。', 'JR品川駅港南口から約1km/ゆりかもめお台場海浜公園駅', 1, 0, 1, 0, 0, 0, 0, 1, 'bright', NULL, 1, 1783636248000, 1783636264760);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('4d8c6a21-051f-42bb-9168-9d9c47778c96', 'saga-castle-moat', '佐賀城公園(お堀周回)', 'さがじょうこうえん(おほりしゅうかい)', '佐賀県', '佐賀市', 33.249288, 130.295487, '佐賀城跡を囲む幅の広いお堀の外周を一周する約3.6kmの周回コース。堀の内側には佐賀城本丸歴史館や佐賀県立博物館・美術館が集まり、クスノキの並木や堀端の遊歩道を眺めながらフラットに走れる。1周がちょうどウォームアップやインターバルの単位にしやすい距離で、周回を重ねて距離調整しやすい。公園内にトイレ・自販機あり。佐賀駅から南へ約2kmでアクセスも良い。', 'JR佐賀駅から南へ約2km / 佐賀駅バスセンターから博物館前バス停', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783638283000, 1783638283962);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('e44ed47e-7ce9-4ef6-ad83-34c3fd7fe88e', 'saigawa-kasenjiki', '犀川緑地', 'さいがわりょくち', '石川県', '金沢市', 36.54023, 136.677401, '大桑防災拠点広場(通称ぐるぐる広場)を起点に、犀川左岸の河川敷園路を下流へ進み、桜橋・犀川大橋を越えたあたりで折り返す往復約8.7km。ほぼフラットで芝生区間と舗装路を選んで走れ、河川敷のトイレが数kmおきにあるのでロング走にも使いやすい。カモなどの野鳥が多く、上流側は医王山方面の山並みも見える。', '起点の大桑防災拠点広場に無料駐車場あり。金沢駅から車で約15分', 1, 0, 0, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783637356000, 1783637357160);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('669d786d-d00d-4607-a88b-391cb20bc2f4', 'saiko-loop', '西湖', 'さいこ', '山梨県', '南都留郡富士河口湖町', 35.50059, 138.662274, '富士五湖のひとつ西湖を湖畔道路でぐるり1周する約9.8km。1km毎の距離看板が設置され、信号がなくペースを刻みやすいため、実業団や大学駅伝チームの合宿でも使われる定番の周回コース。南岸からは湖越しに富士山を望める。歩道のない区間があるので車には注意。根場浜など各浜に駐車場とトイレがあり、南岸には温泉施設「西湖温泉いずみの湯」もある。', '河口湖駅から西湖周遊バスで約30分。根場浜などに無料駐車場あり', 1, 0, 1, 0, 0, 1, 1, 0, 'dark', NULL, 1, 1783639088000, 1783639090120);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('f8deb939-081d-4be9-ada8-d03844ec7f25', 'sanbesan-loop', '三瓶山周回', 'さんべさんしゅうかい', '島根県', '大田市', 35.155617, 132.620094, '国立公園三瓶山の山麓を、北の原キャンプ場を起点に東の原・三瓶温泉・西の原と反時計回りに一周する約15kmのロードコース。男三瓶山を常に横目に見ながら走り、西の原と東の原では草原越しに山容が大きく開ける。獲得標高約360mとアップダウンが連続するので脚づくりの練習に最適。歩道のない区間が多く車には注意。北の原・西の原・東の原に駐車場とトイレがあり、南麓の三瓶温泉で走った後に日帰り入浴もできる。', 'JR大田市駅からバスで約40分。北の原・西の原などに無料駐車場あり', 1, 0, 1, 0, 0, 1, 1, 0, 'dark', NULL, 1, 1783639088000, 1783639091559);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('fef063cb-2c0d-4f54-ae66-9ef3082237a2', 'satsukiyama-ikeda-trail', '五月山・ようらく台園地', 'さつきやま・ようらくだいえんち', '大阪府', '池田市', 34.821823, 135.425623, '阪急池田駅から五月山公園へ上がり、日の丸展望台・五月平展望台を結ぶ遊歩道と五月山ドライブウェイ沿いに東進してようらく台園地方面へ。東斜面のトレイルで下山し市街地を駅へ戻る約12.3kmの周回。標高315mの低山ながら累積約480mあり、展望台からは大阪平野や伊丹空港を一望できる。五月山公園にトイレ・自販機あり。夜景の名所だが山中は照明がないため明るい時間帯の走行が前提。', '阪急宝塚線 池田駅', 1, 0, 1, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783635436000, 1783635450223);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('c18301fc-77f8-420c-a231-11f57fecdb08', 'sayama-hills-totoro-trail', '狭山丘陵・六道山公園トレイル', 'さやまきゅうりょう・ろくどうやまこうえんとれいる', '埼玉県', '所沢市', 35.78499, 139.397177, '早稲田大学所沢キャンパス西側から狭山丘陵の尾根道に入り、都県境の雑木林を縫って瑞穂町の六道山公園まで往復する約8.7kmのトレイル。砂利と土の路面で起伏は緩やかなのでトレイル入門にも向く。六道山公園の展望台は関東の富士見百景に選ばれ、晴れた日には富士山が見える。公園にトイレ・自販機あり。一帯は『となりのトトロ』の舞台モデルと言われる「トトロの森」の保全地域で、四季の里山風景が楽しめる。', '西武池袋線 小手指駅からバス「早稲田大学」下車すぐ', 1, 0, 1, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783635436000, 1783635450746);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('e4f3c11c-4f71-4c3a-b8f1-6f493c25166a', 'sayamako-loop', '狭山湖一周', 'さやまこいっしゅう', '埼玉県', '所沢市', 35.770297, 139.418611, '狭山湖(山口貯水池)の堰堤を起点に、湖を囲む森の未舗装林道と都立野山北・六道山公園の尾根道をつないで一周する約17.8kmのコース。南側は一般車両が入らない土の道が続き、木陰が多く夏でも走りやすい。六道山展望台からは空気が澄んだ日に富士山も望める。北側は車も通る砂利道で雨後はぬかるみに注意。湖面の展望は東側の堰堤付近がハイライト。', '西武狭山線・山口線西武球場前駅から約1.5km', 1, 1, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783636248000, 1783636265275);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('ab63cc3f-f242-42b9-b36d-db38536da702', 'shichikasho-henro-run', '七ヶ所まいり遍路道', 'ななかしょまいりへんろみち', '香川県', '三豊市', 34.226436, 133.722885, '道の駅ふれあいパークみのを起点に、四国霊場71番弥谷寺から77番道隆寺までの7ヶ寺を巡る「七ヶ所まいり」の道を一筆書きで回る約30kmの周回。弥谷寺の540段の石段に始まり、曼荼羅寺への竹林の遍路道、善通寺の大伽藍、多度津の道隆寺から海岸寺経由で戻る。遍路道標が要所にあり、市街区間はコンビニ・自販機の補給に困らない。起点の道の駅には温泉「天然いやだに温泉大師の湯」と駐車場がある。獲得標高約520m。', 'JR予讃線みの駅から約1km。道の駅ふれあいパークみのに駐車場', 1, 0, 1, 0, 0, 1, 1, 1, 'dark', NULL, 1, 1783640240000, 1783640241994);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('5be915c6-95a3-4e5e-8d51-0d646284d4e2', 'shimanto-sada-chinkabashi', '四万十川・佐田沈下橋', 'しまんとがわ・さだちんかばし', '高知県', '四万十市', 32.984245, 132.940409, '中村市街の東側から四万十川左岸の堤防道を上流へたどり、最下流の沈下橋である佐田沈下橋(全長約290m)を渡って対岸へ。右岸は入田の集落と田園を縫って下り、赤鉄橋の愛称で知られる四万十川橋で再び左岸へ戻る約18.8kmの周回。右岸側は小刻みなアップダウンが続き獲得標高は約300m。市街を離れると補給ポイントが少ないので飲料持参が安心。佐田沈下橋のたもとにトイレと駐車場がある。', '土佐くろしお鉄道中村駅から約2km', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640240000, 1783640242231);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b4504719-ea27-4008-b608-673c68e2f885', 'shinminato-kaiwomaru-loop', '海王丸パーク・内川周回', 'かいおうまるぱーく・うちかわしゅうかい', '富山県', '射水市', 36.780267, 137.106315, '帆船海王丸が係留される海王丸パークを起点に、新湊大橋を見上げる越ノ潟から「日本のベニス」と呼ばれる内川沿いへ入り、西端の六渡寺から庄川河口右岸を経て、奈呉の浦の海岸沿いを東進して戻る約12kmの周回コース。富山湾越しの立山連峰、漁船が並ぶ内川の橋めぐり、白い斜張橋の新湊大橋と見どころが続く。全体にフラットで、海王丸パークと川の駅新湊にトイレ・自販機あり。', '万葉線 海王丸駅すぐ', 1, 0, 1, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783638283000, 1783638286399);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('ffa34c79-4ff0-47e1-9508-bbf73d340b04', 'shirahama-engetsu', '白浜・円月島(臨海浦)', 'しらはまえんげつとう', '和歌山県', '西牟婁郡白浜町', 33.684881, 135.344598, '白浜温泉の御船足湯付近から海沿いの県道を北へ走り、中央に丸い海蝕洞が開いた円月島(高嶋)を正面に見ながら臨海浦へ向かう往復コース。京都大学白浜水族館のある番所山公園の園路を回って折り返す。潮の香りの中を走れるフラット基調の道で、朝日・夕日どちらの時間帯も景色が映える。ゴール後は足湯で脚を休められる。', 'JR白浜駅から明光バスで臨海方面へ約15分。円月島前に駐車場あり', 1, 0, 0, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783637164000, 1783637178444);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('1ecf7fd0-3534-495c-8a0d-db815da1df7f', 'shonan-kaigan-cycling-road', '湘南海岸サイクリングロード', 'しょうなんかいがんさいくりんぐろーど', '神奈川県', '藤沢市', 35.308128, 139.4808, '江の島入口の片瀬西浜から鵠沼・辻堂海浜公園・サザンビーチちがさきを経て、相模川河口の湘南大橋まで海岸沿いの自転車歩行者道を走る往復22km。全区間信号なしでハーフマラソン練習にちょうどよく、海水浴場のトイレや自販機が数kmごとに現れる。晴れた日は江の島・烏帽子岩・箱根の山越しの富士山を眺めながら走れる。強い南風の翌日は路面に砂が積もる区間がある点だけ注意。', '小田急江ノ島線片瀬江ノ島駅・江ノ島電鉄江ノ島駅から徒歩約5分', 1, 0, 1, 0, 0, 0, 1, 1, 'partial', NULL, 1, 1783634569000, 1783634581591);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('6951c8c9-e951-4817-8a1b-4e1760d6fc9d', 'takachiho-tetsudo-ato', '五ヶ瀬川渓谷(日向八戸〜槇峰)', 'ごかせがわけいこく(ひゅうがやと〜まきみね)', '宮崎県', '西臼杵郡日之影町', 32.623592, 131.416693, '2005年の台風被害で廃線となった高千穂鉄道の日向八戸駅跡付近を起点に、五ヶ瀬川の渓谷に沿う県道を槇峰駅跡方面まで走って折り返す約9kmの往復コース。川の対岸や頭上に旧線の橋りょうやトンネルが残り、渓谷美と廃線遺構を同時に楽しめる山あいのルート。交通量は少ないが歩道のない区間が多く、緩やかなアップダウンが続く(獲得約210m)。商店や自販機は集落に限られるため補給は事前に。', '北方延岡道路 蔵田ICから車で約15分(公共交通は路線バスのみ)', 0, 0, 0, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783638283000, 1783638285423);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('fcde1967-f80a-4ef4-91a9-ef0ad8f04854', 'takamatsu-kaigan-yashima', '高松港・屋島海岸線', 'たかまつこう・やしまかいがんせん', '香川県', '高松市', 34.349407, 134.043119, '高松港西側の岸壁からサンポート高松のプロムナードを抜け、赤灯台「せとしるべ」を望みつつ瀬戸内の海沿いを東へ。詰田川・春日川の河口を渡り、屋島西町の相引川河口付近まで走る約6.3kmの片道コース。ほぼ平坦で、朝は海越しに屋島と島影が朝日に照らされる。折り返せば約13kmの練習コースになる。', 'JR高松駅・ことでん高松築港駅からすぐ', 1, 0, 0, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783640240000, 1783640241749);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('60e3edc5-dbb3-49f0-b982-fbcb41aa0459', 'takao-inariyama-loop', '高尾山稲荷山コース周回', 'たかおさんいなりやまこーすしゅうかい', '東京都', '八王子市', 35.632202, 139.270051, '清滝駅前から尾根通しの稲荷山コースで登り、もみじ台を踏んでから高尾山頂(599m)へ。下りは琵琶滝のかかる沢沿いの6号路で戻る周回。舗装された1号路と違い登り下りとも土の道で、ケーブルカー圏より人が少なく走りやすい。山頂手前には長い階段、6号路下部には飛び石の渡渉区間がある。山頂と清滝周辺にトイレ・売店・自販機が揃い、下山後はそのまま高尾山口駅併設の温泉に立ち寄れる。距離が短めなのでトレラン初挑戦にも向く。', '京王高尾山口駅から清滝駅前まで徒歩約5分', 1, 0, 1, 0, 0, 1, 0, 0, 'dark', NULL, 1, 1783634569000, 1783634582648);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('05d05d10-64ce-433a-a184-35a975137411', 'tama-kyuryo-hashimoto-wakabadai', '多摩丘陵縦走(尾根緑道・よこやまの道)', 'たまきゅうりょうじゅうそう(おねりょくどう・よこやまのみち)', '神奈川県', '相模原市緑区', 35.595004, 139.344989, '橋本駅から多摩丘陵の尾根をつないで若葉台駅まで走り抜ける約21kmのワンウェイ。戦車のテスト走行路だった歴史を持つ尾根緑道を東へ、谷戸と雑木林が残る都立小山田緑地を抜け、多摩ニュータウンの南縁に続く多摩よこやまの道の尾根道へとつなぐ。舗装の緑道と土の道が交互に現れ、ロードとトレイルの両方を一度に楽しめる。丘陵らしい小刻みな起伏で獲得標高は約300m。緑道沿いや公園に公衆トイレが点在し、発着どちらも駅前で補給できる。', '起点はJR横浜線・京王相模原線橋本駅、終点は京王相模原線若葉台駅', 1, 0, 0, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783634569000, 1783634583694);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('a34fb409-8527-4ea9-b8dc-104169eef6c3', 'tazawako-loop', '田沢湖', 'たざわこ', '秋田県', '仙北市', 39.734272, 140.697601, '水深日本一の田沢湖を湖畔道路で回る一周約20.6km。東岸の田沢湖畔(白浜)エリアを起点に反時計回りで約9km走ると西岸・潟尻の金色のたつこ像に着き、売店や食事処で小休止できる。ほぼ湖面を見ながら走れるフラット基調の周回で、田沢湖マラソンの舞台としても知られる。周辺に温泉が多く走った後の入浴にも困らない。', 'JR田沢湖駅からバス約12分「田沢湖畔」下車。湖畔に駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783637356000, 1783637357656);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('abdf3854-6bf2-4445-999a-970b6b9de6b3', 'tobishima-loop', '飛島(勝浦港周回)', 'とびしま', '山形県', '酒田市', 39.184953, 139.546748, '酒田港から定期船「とびしま」で約75分、山形県唯一の離島・飛島をめぐる周回コース。勝浦港のフェリーターミナルを起点に南の館岩付近を回り、島の中央を貫く農免農道と林道で北端近くまで縦断、法木集落から海沿いの県道で戻る。ジオパークらしい奇岩の海岸線と原生林が続く。分岐が多いので案内板の確認を忘れずに。船は季節ダイヤのため帰りの便を要確認。', '酒田港から定期船「とびしま」で約75分、勝浦港下船すぐ', 1, 0, 0, 0, 0, 0, 0, 0, 'dark', NULL, 1, 1783637164000, 1783637178677);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('944b5b88-408c-4283-b88e-402b7a708d01', 'tojinbo-mikuni-loop', '東尋坊・三国湊', 'とうじんぼう・みくにみなと', '福井県', '坂井市', 36.221234, 136.136224, '三国温泉ゆあぽーと前を起点に、九頭竜川河口の三国湊の町並みを抜けて北上し、東尋坊の断崖上を小さく周回、雄島橋で折り返して越前海岸沿いに戻る約12.6kmの周回コース。東尋坊は柱状節理の岩壁が続く景勝地で、商店街にトイレ・売店・自販機がある。アップダウンは緩やかで獲得標高は約140m。', 'えちぜん鉄道三国港駅から約500m。東尋坊・三国サンセットビーチに駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640240000, 1783640240812);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('56c266c6-02e6-4210-bdb8-2f9b3c41dc7e', 'tsunoshima-bridge', '角島大橋・角島灯台', 'つのしまおおはし・つのしまとうだい', '山口県', '下関市', 34.30608, 130.918911, 'JR特牛駅を起点に海士ヶ瀬公園まで北上し、全長約1780mの角島大橋でコバルトブルーの海峡を渡って島を横断、西端の角島灯台公園で折り返して橋を渡り返し、ホテル西長門リゾート前まで走る約20.6km。橋の上は路肩が狭いので車に十分注意。トイレは海士ヶ瀬公園と灯台公園にあり、島内にも自販機がある。丘越えが続き獲得標高は約300m。', 'JR山陰本線特牛駅からスタート。海士ヶ瀬公園に無料駐車場あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783639088000, 1783639089152);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('f4f2cb70-920f-4569-a8d5-b6cd915d1449', 'tsurumigawa-tsunashima', '鶴見川・新横浜公園', 'つるみがわ・しんよこはまこうえん', '神奈川県', '横浜市港北区', 35.536584, 139.634186, '東急東横線綱島駅から大綱橋で鶴見川の土手に上がり、新羽橋・亀甲橋を経て新横浜公園まで遡上、日産スタジアムの外周をぐるりと回って同じ土手を戻る約14kmのコース。土手上は信号がなくペースを刻みやすい。新横浜公園内にはトイレ・自販機・周回園路が揃い距離調整もしやすい。綱島駅周辺には日帰り温泉があり、走った後に汗を流して帰れるのも魅力。', '東急東横線 綱島駅', 1, 0, 1, 0, 0, 1, 0, 1, 'partial', NULL, 1, 1783635436000, 1783635448650);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('15176df4-7d58-4f56-baa4-0fd141691782', 'utsukushigahara-trail', '美ヶ原高原(王ヶ頭・王ヶ鼻)', 'うつくしがはらこうげん', '長野県', '上田市', 36.229546, 138.138021, '標高約2,000mの美ヶ原の台上をたどる往復トレイル。道の駅美ヶ原高原を起点に、牛が放牧される草原の中を美しの塔・塩くれ場と進み、最高点の王ヶ頭(2,034m)から展望地の王ヶ鼻まで足を延ばす。視界を遮るものがほぼなく、天気が良ければ北アルプスや富士山まで見渡せる。真夏でも涼しく避暑トレーニングに向くが、春秋は防寒必須。', '道の駅美ヶ原高原(美術館)駐車場が起点。マイカー利用が基本で、県道は冬季閉鎖あり', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783637164000, 1783637177736);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('6ec2c6d1-a955-4b06-87d6-778a115c8763', 'wangan-ariake-kasai', '湾岸ロング(有明〜若洲〜葛西)', 'わんがんろんぐ(ありあけ〜わかす〜かさい)', '東京都', '江東区', 35.631737, 139.792364, '有明北の水辺を起点に、辰巳・新木場から若洲海浜公園で東京ゲートブリッジのたもとへ、さらに荒川河口橋を渡って葛西臨海公園まで足を延ばして折り返す約31.8kmのロング走コース。信号待ちは序盤の数カ所程度で、湾岸の埋立地をほぼノンストップで走り続けられる。若洲・夢の島・葛西臨海公園と公衆トイレが点在する一方、コンビニは新木場周辺などに限られるため補給は計画的に。観覧車や対岸の景色が単調さを紛らわせてくれる。', 'ゆりかもめ 有明テニスの森駅/りんかい線 国際展示場駅', 1, 0, 1, 0, 0, 0, 0, 0, 'partial', NULL, 1, 1783635436000, 1783635450478);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('5db7e607-3218-4bb9-8707-73044c9599f3', 'yamagata-city-loop', '山形市中心部(霞城公園・文翔館)', 'やまがたしちゅうしんぶ', '山形県', '山形市', 38.247744, 140.324193, '山形駅西口を起点に市内の名所をつなぐ周回コース。山形城跡の霞城公園を園路でめぐり、東大手門から里之宮湯殿山神社、レンガ造りの旧県庁舎・文翔館へ。馬見ヶ崎橋で川を眺めて折り返し、七日町大通りを南下して駅へ戻る。信号は多めだが道はフラットで、公園の桜(春)や歴史的建築を楽しみながら走れる街ラン向きの一周。', 'JR山形駅西口からすぐ', 1, 0, 1, 0, 0, 0, 0, 1, 'partial', NULL, 1, 1783637164000, 1783637178912);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('310b8968-934f-4bec-ace5-c83019fb4f01', 'yamanakagoe-tetsugaku', '山中越・哲学の道', 'やまなかごえ・てつがくのみち', '滋賀県', '大津市', 35.050011, 135.866889, '京阪滋賀里駅を起点に、比叡山南麓の山中越(県道30号)で山中町の峠集落を越えて京都・北白川へ下る片道コース。銀閣寺橋からは琵琶湖疏水分線沿いの哲学の道を南下し、南禅寺の水路閣がゴール。前半で約350mを登る本格的な峠走、後半は桜並木の静かな小径と、雰囲気の違いを楽しめる。', '起点は京阪石山坂本線滋賀里駅。ゴールの南禅寺から地下鉄蹴上駅まで徒歩約10分', 1, 0, 0, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783640625000, 1783640627410);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('95052634-ec79-4dbd-8c26-39c178cc9f35', 'yashima-loop', '屋島', 'やしま', '香川県', '高松市', 34.361817, 134.09174, '屋島西町から屋島の裾を反時計回りに一周する約13.6kmのロード周回。西海岸を北上して浦生の集落を過ぎ、最北端の長崎ノ鼻まで足を延ばして折り返し、北の鞍部を越えて東海岸へ。相引川沿いを回って戻る。信号がほとんどなく交通量も少なめで、北部の峠越えを中心に獲得標高約200mのアップダウンがある。途中から屋島北嶺への登山道に取り付くこともできる。', 'ことでん屋島駅・潟元駅から徒歩圏。周辺に入浴施設あり', 0, 0, 0, 0, 0, 0, 1, 0, 'partial', NULL, 1, 1783640240000, 1783640241516);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('0dc2e95b-6570-4f0e-aaad-466376bdb53e', 'yokote-park', '横手公園', 'よこてこうえん', '秋田県', '横手市', 39.310342, 140.560839, 'JR横手駅を起点に横手川を渡り、模擬天守の横手城展望台が建つ城山の横手公園と園内の池・牛沼をめぐって戻る約5kmの周回。城山への登り坂で短いながらしっかり心拍が上がる。桜の名所で春は花見ランにも良い。園内にトイレがあり、駅そばの温浴施設をランステ代わりに使える。', 'JR横手駅から徒歩すぐが起点。駅周辺にコインパーキングあり', 1, 0, 0, 0, 0, 1, 0, 0, 'partial', NULL, 1, 1783637356000, 1783637357890);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('27dadc3e-044e-4db3-9d57-26db64b6838b', 'yokoyama-no-michi-oyamada', '多摩よこやまの道・小山田緑地', 'たまよこやまのみち・おやまだりょくち', '神奈川県', '川崎市麻生区', 35.60133, 139.482602, '小田急多摩線・栗平駅近くを起点に、鶴川台の緑道から真光寺公園、江戸期の古道・布田道を経て多摩丘陵の尾根をたどる「多摩よこやまの道」を西へ進み、都立小山田緑地まで足を延ばす約23kmの周回ロング。復路は鶴見川の谷を芝溝街道・鶴川駅前経由で戻る。尾根道は土やウッドチップの走りやすい路面で、南野・永山にトイレ、小山田緑地に駐車場あり。', '小田急多摩線栗平駅から約400m', 1, 0, 1, 0, 0, 0, 1, 1, 'dark', NULL, 1, 1783636248000, 1783636264263);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('fe5776d2-c986-44a7-a898-57f413763fd9', 'yoro-daifukuyama', '大福山・養老渓谷', 'だいふくやま・ようろうけいこく', '千葉県', '市原市', 35.254604, 140.145535, '小湊鉄道養老渓谷駅を起点に、林道女ヶ倉線で梅ヶ瀬渓谷入口を過ぎて大福山(約285m)まで登り、下山後は養老川沿いの温泉街と弘文洞跡方面を巡って駅へ戻る約17.9kmの周回。房総の深い森を縫う舗装林道は交通量が少なく、累積約630mでしっかり走り込める。駅と温泉街にトイレ・自販機、駅前に売店あり。梅ヶ瀬渓谷の沢沿い道は徒渉が多い登山道のため、本コースは林道経由で設計している。', '小湊鉄道 養老渓谷駅', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783635436000, 1783635449968);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('9b9a42a5-9fda-41df-b1e6-bdb456e36112', 'yunoko-lake', '湯ノ湖', 'ゆのこ', '栃木県', '日光市', 36.805307, 139.424369, '標高約1475mに位置する奥日光・湯ノ湖を一周し、南端から湯滝の観瀑台へ短い坂を往復する約3.5km。西岸は森の中を行く不整地のトレイル、東岸は国道沿いの湖畔道で、日光湯元温泉の宿から直接走り出せる。真夏でも涼しく高地トレーニング気分が味わえる。', '湯元温泉バス停(東武日光駅からバス約80分)からすぐ。湖畔に無料駐車場あり', 1, 0, 0, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783640625000, 1783640626672);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('6a354e62-2288-4bfb-936b-4e5fa19fe87d', 'yutoku-inari-ariake', '祐徳稲荷神社〜大魚神社海中鳥居', 'ゆうとくいなりじんじゃ〜おおうおじんじゃかいちゅうとりい', '佐賀県', '鹿島市', 33.095601, 130.117211, 'JR肥前浜駅を起点に、白壁の酒蔵が並ぶ肥前浜宿を抜けて九州屈指の稲荷社・祐徳稲荷神社へ向かい、参拝後は有明海側へ折り返して太良町の大魚神社海中鳥居まで南下する約18kmのワンウェイ。ゴール後はJR多良駅から列車で戻れる。海中鳥居は干潮時に鳥居の下まで歩ける干満差の大きい有明海ならではのスポット。アップダウンは祐徳稲荷周辺のみで、後半は海を感じる開放的な平坦路が続く。', 'JR長崎本線 肥前浜駅(スタート) / 多良駅(ゴール)', 1, 0, 1, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783638283000, 1783638284198);
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('1e3a6718-8dad-4fb6-9d1b-8f2136ac1127', 'zushi-hayama-trail', '三浦アルプス縦走(二子山〜仙元山)', 'みうらあるぷすじゅうそう(ふたごやま〜せんげんやま)', '神奈川県', '逗子市', 35.295278, 139.580731, '京急逗子・葉山駅を発着し、南郷上ノ山公園からトレイルへ。二子山(208m)から乳頭山・茅塚・観音塚と三浦アルプスの主稜線をつなぎ、最後は仙元山(118m)から相模湾と江の島、晴れれば富士山を望んで葉山の街へ下る周回。標高は低いが細かいアップダウンが延々と続き、距離以上に脚にくる。稜線は分岐が非常に多いので地図アプリ必携。トイレは南郷上ノ山公園と仙元山のみで、トレイル中に自販機はない。', '京急逗子線逗子・葉山駅からすぐ(南口周辺にコンビニ・コインロッカーあり)', 1, 0, 0, 0, 0, 0, 0, 1, 'dark', NULL, 1, 1783634569000, 1783634581859);
